INSERT INTO places (id, name, aliases, description, type, importance, longitude, latitude, periods, period_notes, certainty, related_place_ids, source_ids) VALUES ('p_guangzhou', '广州', ARRAY['番禺', 'Guangzhou', 'Canton']::TEXT[], '中国最重要的对外贸易港口之一，海上丝绸之路的重要起点。', 'port', 'high', 113.2644, 23.1291, ARRAY['han', 'tang', 'mongol']::TEXT[], '[{"period_id":"tang","note":"设市舶司管理对外贸易，番坊有大量外商居住。"}]'::jsonb, 'confirmed', ARRAY['p_quanzhou', 'p_malacca']::TEXT[], ARRAY['s4', 's5']::TEXT[]) ON CONFLICT (id) DO NOTHING;
