INSERT INTO places (id, name, aliases, description, type, importance, longitude, latitude, periods, period_notes, certainty, related_place_ids, source_ids) VALUES ('p_ningbo', '宁波', ARRAY['明州', 'Ningbo']::TEXT[], '中国重要的港口城市，通往日本和高丽的主要港口。', 'port', 'medium', 121.5439, 29.8683, ARRAY['tang', 'mongol']::TEXT[], '[{"period_id":"tang","note":"遣唐使多在明州登陆。"}]'::jsonb, 'confirmed', ARRAY['p_quanzhou', 'p_hangzhou']::TEXT[], ARRAY[]::TEXT[]) ON CONFLICT (id) DO NOTHING;
INSERT INTO places (id, name, aliases, description, type, importance, longitude, latitude, periods, period_notes, certainty, related_place_ids, source_ids) VALUES ('p_hangzhou', '杭州', ARRAY['临安', 'Hangzhou', 'Kinsay']::TEXT[], '南宋都城，大运河的南端起点，物产丰饶。', 'capital', 'high', 120.1551, 30.2741, ARRAY['tang', 'mongol']::TEXT[], '[{"period_id":"mongol","note":"马可波罗惊叹其为‘世界上最美丽华贵之天城’。"}]'::jsonb, 'confirmed', ARRAY['p_changan', 'p_ningbo']::TEXT[], ARRAY['s3']::TEXT[]) ON CONFLICT (id) DO NOTHING;
